import { AfterViewInit, Component, Input, OnChanges, OnInit, SimpleChanges, ViewChild } from '@angular/core';
import { ChartDataSets, ChartOptions, ChartType } from 'chart.js';
import { BaseChartDirective, Color, Label } from 'ng2-charts';
import { MonthCount } from '../stats.component';

interface BrandStats {
  id: string;
  value: number;
  region: string;
}
@Component({
  selector: 'app-line-visualization',
  templateUrl: './line-visualization.component.html',
  styleUrls: ['./line-visualization.component.scss'],
})
export class LineVisualizationComponent implements OnInit, OnChanges {
  isLineChart: boolean = true;
  toggleChartType() {
    this.isLineChart = !this.isLineChart;
  }
  public lineChartData: ChartDataSets[] = [
    {
      data: [],
      label: 'Scans',
    },
  ];
  // public width;
  public lineChartLabels: Label[] = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ];
  public lineChartOptions: ChartOptions & { annotation: any } = {
    responsive: true,
    annotation: {},
  };
  public lineChartColors: Color[] = [
    {
      backgroundColor: 'rgb(118 156 162 / 0.2)',
      borderColor: 'rgba(118, 156, 162,1)',
      pointBackgroundColor: 'rgba(148,159,177,1)',
      pointBorderColor: '#fff',
      pointHoverBackgroundColor: '#fff',
      pointHoverBorderColor: 'rgba(148,159,177,0.8)',
    },
  ];
  public lineChartLegend = true;
  public lineChartType: ChartType = 'line';

  @Input() selectedList: number;

  @Input() scansCount: MonthCount[];
  @Input() scansWithoutAuth: MonthCount[];
  @Input() productsCount: MonthCount[];

  @ViewChild(BaseChartDirective, { static: true }) chart: BaseChartDirective;

  constructor() {}

  ngOnInit(): void {
      if (this.selectedList === 0) {
        this.setupData(this.scansCount);
      } else if (this.selectedList === 1) {
        this.setupData(this.scansWithoutAuth);
      } else {
        this.setupData(this.productsCount);
      }
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['scansCount'] || changes['selectedList']) {
        if (this.selectedList === 0) {
          this.setupData(this.scansCount);
        } else if (this.selectedList == 1) {
          this.setupData(this.scansWithoutAuth);
        } else {
          this.setupData(this.productsCount);
        }
    }
  }

  setupData(list: MonthCount[]) {
    var data: number[] = [];
    for (var i = 0; i < 12; i++) {
      data.push(list[i].count);
    }
    this.lineChartData = [
      {
        data,
        label: this.selectedList === 1 ? "Products" : 'Scans',
      },
    ];
    this.chart.chart.data.datasets[0].data = data;
    this.chart.chart.update();
  }

  public chartClicked({
    event,
    active,
  }: {
    event: MouseEvent;
    active: {}[];
  }): void {
    console.log(event, active);
  }

  public chartHovered({
    event,
    active,
  }: {
    event: MouseEvent;
    active: {}[];
  }): void {}

  public hideOne(): void {
    const isHidden = this.chart.isDatasetHidden(1);
    this.chart.hideDataset(1, !isHidden);
  }

  public changeLabel(): void {
    this.lineChartLabels[2] = ['1st Line', '2nd Line'];
  }
}
